//! Image generation via Gemini's native multimodal output.
//! Uses `responseModalities: ["TEXT", "IMAGE"]` — the model returns both
//! a text description and a base64-encoded PNG inline.
//!
//! We discard the text and extract only the image data.

use base64::Engine;
use rand::Rng;
use serde_json::{json, Value};

use super::{ConnectionDto, ProviderError};

fn api_err(status: u16, msg: impl Into<String>) -> ProviderError {
    ProviderError::Api {
        status,
        message: msg.into(),
    }
}

/// Calls Gemini and returns the generated image as raw PNG bytes.
pub async fn generate_image(
    connection: &ConnectionDto,
    api_key: &str,
    prompt: &str,
) -> Result<Vec<u8>, ProviderError> {
    let client = reqwest::Client::new();
    let url = format!(
        "https://generativelanguage.googleapis.com/v1beta/models/{}:generateContent",
        connection.model
    );

    let body = json!({
        "contents": [{
            "parts": [{ "text": prompt }]
        }],
        "generationConfig": {
            "responseModalities": ["TEXT", "IMAGE"],
            "imageConfig": {
                "aspectRatio": "1:1",
                "imageSize": "1K"
            }
        }
    });

    let res = client
        .post(&url)
        .header("x-goog-api-key", api_key)
        .json(&body)
        .send()
        .await?;

    let status = res.status();
    let text = res.text().await?;

    if !status.is_success() {
        return Err(api_err(status.as_u16(), text));
    }

    let v: Value = serde_json::from_str(&text).map_err(|e| api_err(200, format!("Invalid JSON: {e}")))?;
    let parts = v["candidates"][0]["content"]["parts"]
        .as_array()
        .ok_or_else(|| api_err(200, "No parts in Gemini image response"))?;

    for part in parts {
        if let Some(inline) = part["inlineData"].as_object() {
            if inline.get("mimeType").and_then(|m| m.as_str()) == Some("image/png") {
                if let Some(b64) = inline.get("data").and_then(|d| d.as_str()) {
                    return base64::engine::general_purpose::STANDARD
                        .decode(b64)
                        .map_err(|e| api_err(200, format!("Failed to decode base64 image: {e}")));
                }
            }
        }
    }

    Err(api_err(200, "No image data found in Gemini response"))
}

/// Free image generation via pollinations.ai — no API key needed.
/// Wraps Stable Diffusion behind a simple GET endpoint.
/// Falls back when Gemini is geo-blocked.
///
/// `target_type` is `"fact"` or `"inventory"` — used to select
/// style keywords that guide the model toward the right visual genre.
pub async fn generate_image_free(prompt: &str, target_type: &str) -> Result<Vec<u8>, ProviderError> {
    let client = reqwest::Client::new();
    let seed: u64 = rand::thread_rng().gen();

    // Style prefix based on target type — gives Pollinations a genre hint.
    let style_prefix = match target_type {
        "fact" => "fantasy illustration, detailed, atmospheric",
        "inventory" => "RPG item icon, detailed, clean background",
        _ => "fantasy illustration, detailed, atmospheric",
    };

    let unique_prompt = format!(
        "{style_prefix}: {prompt}, no text, no watermark [seed:{seed}]"
    );
    let url = format!(
        "https://image.pollinations.ai/prompt/{}?width=512&height=512&nologo=true",
        urlencoding(&unique_prompt)
    );

    let res = client.get(&url).send().await?;
    let status = res.status();
    if !status.is_success() {
        return Err(api_err(status.as_u16(), "Pollinations.ai request failed"));
    }
    res.bytes().await.map(|b| b.to_vec()).map_err(|e| api_err(500, format!("Failed to read image: {e}")))
}

fn urlencoding(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for b in s.bytes() {
        match b {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => out.push(b as char),
            b' ' => out.push_str("%20"),
            _ => out.push_str(&format!("%{:02X}", b)),
        }
    }
    out
}

use std::fs;
use std::io::Cursor;
use std::path::PathBuf;

use tauri::{AppHandle, Manager};

use crate::commands::secrets::get_api_key;
use crate::providers::{self, ConnectionDto};

/// Generates an illustration via Gemini, resizes it to max 512px,
/// and saves it as a PNG in the avatars directory.
/// Returns the absolute filesystem path of the saved file.
#[tauri::command]
pub async fn generate_illustration(
    app: AppHandle,
    connection: ConnectionDto,
    prompt: String,
    target_type: String,
) -> Result<String, String> {
    let api_key = get_api_key(&connection.id)
        .map_err(|e| e.to_string())?
        .ok_or_else(|| "Pro toto připojení není uložen žádný API klíč.".to_string())?;

    // Try Gemini first, fall back to free Pollinations.ai if geo-blocked
    let image_bytes = match providers::image_gen::generate_image(&connection, &api_key, &prompt).await {
        Ok(bytes) => bytes,
        Err(e) => {
            let msg = e.to_string();
            if msg.contains("not available in your country") || msg.contains("FAILED_PRECONDITION") {
                providers::image_gen::generate_image_free(&prompt, &target_type).await.map_err(|e| e.to_string())?
            } else {
                return Err(msg);
            }
        }
    };

    // Resize to max 512px on the longer side — icons and avatars don't
    // need more, and smaller files load faster in the UI.
    let resized = resize_max(&image_bytes, 512)
        .map_err(|e| format!("nepodařilo se zmenšit obrázek: {e}"))?;

    let dir = avatars_dir(&app)?;
    let filename = format!("illustration_{}.png", uuid::Uuid::new_v4());
    let dest = dir.join(&filename);
    fs::write(&dest, &resized)
        .map_err(|e| format!("nepodařilo se uložit obrázek: {e}"))?;

    Ok(dest.to_string_lossy().to_string())
}

/// Resizes a PNG to at most `max_dim` pixels on the longer side,
/// keeping the aspect ratio. Returns the resized PNG bytes.
fn resize_max(png_bytes: &[u8], max_dim: u32) -> Result<Vec<u8>, String> {
    let img = image::load_from_memory(png_bytes)
        .map_err(|e| format!("nepodařilo se načíst obrázek: {e}"))?;

    let (w, h) = (img.width(), img.height());
    if w <= max_dim && h <= max_dim {
        // Already small enough — re-encode as PNG anyway to strip
        // any extra chunks the API might include.
        let mut buf = Cursor::new(Vec::new());
        img.write_to(&mut buf, image::ImageFormat::Png)
            .map_err(|e| format!("nepodařilo se uložit obrázek: {e}"))?;
        return Ok(buf.into_inner());
    }

    let ratio = if w > h {
        max_dim as f64 / w as f64
    } else {
        max_dim as f64 / h as f64
    };
    let new_w = (w as f64 * ratio) as u32;
    let new_h = (h as f64 * ratio) as u32;

    let resized = img.resize_exact(new_w, new_h, image::imageops::FilterType::Lanczos3);
    let mut buf = Cursor::new(Vec::new());
    resized
        .write_to(&mut buf, image::ImageFormat::Png)
        .map_err(|e| format!("nepodařilo se uložit obrázek: {e}"))?;
    Ok(buf.into_inner())
}

fn avatars_dir(app: &AppHandle) -> Result<PathBuf, String> {
    let base = app
        .path()
        .app_data_dir()
        .map_err(|e| format!("nepodařilo se najít adresář aplikace: {e}"))?;
    let dir = base.join("avatars");
    fs::create_dir_all(&dir).map_err(|e| format!("nepodařilo se vytvořit adresář avatarů: {e}"))?;
    Ok(dir)
}

